import{_ as s,o as i,c as l,ae as e}from"./chunks/framework.Czhw_PXq.js";const k=JSON.parse('{"title":"Windows 系统安装","description":"","frontmatter":{},"headers":[],"relativePath":"zh-cn/install/windows.md","filePath":"zh-cn/install/windows.md"}'),n={name:"zh-cn/install/windows.md"};function t(o,a,d,r,h,p){return i(),l("div",null,[...a[0]||(a[0]=[e(`<h1 id="windows-系统安装" tabindex="-1">Windows 系统安装 <a class="header-anchor" href="#windows-系统安装" aria-label="Permalink to &quot;Windows 系统安装&quot;">​</a></h1><h2 id="系统要求" tabindex="-1">系统要求 <a class="header-anchor" href="#系统要求" aria-label="Permalink to &quot;系统要求&quot;">​</a></h2><ul><li><strong>操作系统</strong>: Windows 10 (版本 1903 或更高)、Windows 11</li><li><strong>架构</strong>: x86_64 (AMD64)</li><li><strong>磁盘空间</strong>: 约 200MB 用于 ADB</li></ul><h2 id="安装-android-sdk-platform-tools" tabindex="-1">安装 Android SDK Platform Tools <a class="header-anchor" href="#安装-android-sdk-platform-tools" aria-label="Permalink to &quot;安装 Android SDK Platform Tools&quot;">​</a></h2><h2 id="安装-android-sdk-platform-tools-1" tabindex="-1">安装 Android SDK Platform Tools <a class="header-anchor" href="#安装-android-sdk-platform-tools-1" aria-label="Permalink to &quot;安装 Android SDK Platform Tools&quot;">​</a></h2><h3 id="方式一-下载压缩包" tabindex="-1">方式一：下载压缩包 <a class="header-anchor" href="#方式一-下载压缩包" aria-label="Permalink to &quot;方式一：下载压缩包&quot;">​</a></h3><ol><li>访问 <a href="https://developer.android.com/studio/releases/platform-tools" target="_blank" rel="noreferrer">Android Developer</a></li><li>下载 Windows 版本（platform-tools_rXX-windows.zip）</li><li>解压到合适位置，如 <code>C:\\Android\\Sdk\\platform-tools</code></li></ol><h3 id="方式二-使用包管理器-推荐" tabindex="-1">方式二：使用包管理器（推荐） <a class="header-anchor" href="#方式二-使用包管理器-推荐" aria-label="Permalink to &quot;方式二：使用包管理器（推荐）&quot;">​</a></h3><p>使用 <a href="https://scoop.sh" target="_blank" rel="noreferrer">Scoop</a> 或 <a href="https://chocolatey.org" target="_blank" rel="noreferrer">Chocolatey</a>：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 使用 Scoop</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">scoop install adb</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 使用 Chocolatey</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">choco install adb</span></span></code></pre></div><h2 id="配置环境变量" tabindex="-1">配置环境变量 <a class="header-anchor" href="#配置环境变量" aria-label="Permalink to &quot;配置环境变量&quot;">​</a></h2><ol><li>右键「此电脑」→ 属性 → 高级系统设置</li><li>点击「环境变量」</li><li>在「系统变量」中找到 <code>Path</code>，双击编辑</li><li>添加 ADB 路径，如 <code>C:\\Android\\Sdk\\platform-tools</code></li><li>确定保存</li></ol><h2 id="验证安装" tabindex="-1">验证安装 <a class="header-anchor" href="#验证安装" aria-label="Permalink to &quot;验证安装&quot;">​</a></h2><p>打开命令提示符，输入：</p><div class="language-cmd vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cmd</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">adb version</span></span></code></pre></div><p>应显示类似：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Android Debug Bridge version 1.0.41</span></span>
<span class="line"><span>Version 34.0.5-10900879</span></span></code></pre></div><h2 id="手机设置" tabindex="-1">手机设置 <a class="header-anchor" href="#手机设置" aria-label="Permalink to &quot;手机设置&quot;">​</a></h2><ol><li>开启手机的「开发者选项」 <ul><li>设置 → 关于手机 → 连续点击「版本号」7 次</li></ul></li><li>启用「USB 调试」 <ul><li>设置 → 开发者选项 → USB 调试</li></ul></li><li>确保手机和电脑在同一 WiFi 网络</li></ol><h2 id="adb-连接方式" tabindex="-1">ADB 连接方式 <a class="header-anchor" href="#adb-连接方式" aria-label="Permalink to &quot;ADB 连接方式&quot;">​</a></h2><h3 id="usb-连接" tabindex="-1">USB 连接 <a class="header-anchor" href="#usb-连接" aria-label="Permalink to &quot;USB 连接&quot;">​</a></h3><div class="language-cmd vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cmd</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">adb devices</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">adb usb</span></span></code></pre></div><h3 id="wifi-连接-首次需要-usb" tabindex="-1">WiFi 连接（首次需要 USB） <a class="header-anchor" href="#wifi-连接-首次需要-usb" aria-label="Permalink to &quot;WiFi 连接（首次需要 USB）&quot;">​</a></h3><div class="language-cmd vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cmd</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"># 让手机监听 TCP 端口</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">adb tcpip </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">5555</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"># 断开 USB，通过 WiFi 连接</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">adb connect </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">192.168.1.100</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">5555</span></span></code></pre></div>`,24)])])}const b=s(n,[["render",t]]);export{k as __pageData,b as default};
